    input clk,
    input j,
    input y,
    input reset,
    output reg out);// State Encoding
    parameter OFF = 0, ON = 1;
    reg [1:0] state, next;

    // State Transition Logic
    always @(*) begin
        case (state)
            OFF: next = j ? ON : OFF;
            ON: next = y ? OFF : ON;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) state <= OFF;
        else state <= next;
    end

    // Output Logic
    always @(*) begin
        case (state)
            OFF: out = 0;
            ON: out = 1;
        endcase
    end
